import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;
import org.springframework.data.domain.Sort;
import org.springframework.data.jpa.domain.Specification;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * CRUD and status-workflow service for native tickets (work items).
 */
@Service
@Transactional
public class TicketService {

	private static final Logger log = LoggerFactory.getLogger(TicketService.class);

	/** Valid Fibonacci-scale estimate values (mirrors CommitService). */
	private static final Set<Integer> VALID_ESTIMATE_POINTS = Set.of(1, 2, 3, 5, 8);

	/** Key prefix used when auto-generating ticket keys. */
	private static final String KEY_PREFIX = "T-";

	/** Legal status transitions. */
	private static final Map<TicketStatus, Set<TicketStatus>> ALLOWED_TRANSITIONS = Map.of(TicketStatus.TODO,
			EnumSet.of(TicketStatus.IN_PROGRESS, TicketStatus.CANCELED), TicketStatus.IN_PROGRESS,
			EnumSet.of(TicketStatus.DONE, TicketStatus.BLOCKED, TicketStatus.CANCELED, TicketStatus.TODO),
			TicketStatus.BLOCKED, EnumSet.of(TicketStatus.IN_PROGRESS, TicketStatus.CANCELED, TicketStatus.TODO),
			TicketStatus.DONE, EnumSet.noneOf(TicketStatus.class), TicketStatus.CANCELED,
			EnumSet.of(TicketStatus.TODO));

	private final WorkItemRepository workItemRepo;
	private final WorkItemStatusHistoryRepository historyRepo;
	private final WeeklyCommitRepository commitRepo;
	private final WeeklyPlanRepository planRepo;
	private final NotificationService notificationService;

	/** Optional — injected when the RAG module is active; null-safe throughout. */
	@Autowired(required = false)
	private com.weeklycommit.ai.rag.SemanticIndexService semanticIndexService;

	public TicketService(WorkItemRepository workItemRepo, WorkItemStatusHistoryRepository historyRepo,
			WeeklyCommitRepository commitRepo, WeeklyPlanRepository planRepo, NotificationService notificationService) {
		this.workItemRepo = workItemRepo;
		this.historyRepo = historyRepo;
		this.commitRepo = commitRepo;
		this.planRepo = planRepo;
		this.notificationService = notificationService;
	}

	// -------------------------------------------------------------------------
	// Create
	// -------------------------------------------------------------------------

	public TicketDetailResponse createTicket(CreateTicketRequest req) {
		validateEstimatePoints(req.estimatePoints());

		WorkItem item = new WorkItem();
		item.setTeamId(req.teamId());
		item.setKey(generateKey(req.teamId()));
		item.setTitle(req.title());
		item.setDescription(req.description());
		item.setStatus(req.status() != null ? req.status() : TicketStatus.TODO);
		item.setPriority(req.priority() != null ? req.priority() : TicketPriority.MEDIUM);
		item.setAssigneeUserId(req.assigneeUserId());
		item.setReporterUserId(req.reporterUserId());
		item.setEstimatePoints(req.estimatePoints());
		item.setRcdoNodeId(req.rcdoNodeId());
		item.setTargetWeekStartDate(req.targetWeekStartDate());

		WorkItem saved = workItemRepo.save(item);
		if (semanticIndexService != null) {
			semanticIndexService.indexEntity(com.weeklycommit.ai.rag.SemanticIndexService.TYPE_TICKET, saved.getId());
		}
		return getTicketDetail(saved.getId());
	}

	public TicketDetailResponse createTicketFromCommit(CreateTicketFromCommitRequest req) {
		WeeklyPlan plan = requirePlan(req.planId());
		WeeklyCommit commit = requireCommit(req.commitId());
		if (!commit.getPlanId().equals(plan.getId())) {
			throw new PlanValidationException("Commit " + req.commitId() + " does not belong to plan " + req.planId());
		}

		WorkItem item = new WorkItem();
		UUID teamId = req.teamId() != null ? req.teamId() : plan.getTeamId();
		item.setTeamId(teamId);
		item.setKey(generateKey(teamId));
		item.setTitle(req.title() != null && !req.title().isBlank() ? req.title() : commit.getTitle());
		item.setDescription(req.description() != null ? req.description() : commit.getDescription());
		item.setStatus(req.status() != null ? req.status() : TicketStatus.TODO);
		item.setPriority(req.priority() != null ? req.priority() : TicketPriority.MEDIUM);
		item.setAssigneeUserId(req.assigneeUserId());
		item.setReporterUserId(req.reporterUserId() != null ? req.reporterUserId() : commit.getOwnerUserId());
		validateEstimatePoints(req.estimatePoints() != null ? req.estimatePoints() : commit.getEstimatePoints());
		item.setEstimatePoints(req.estimatePoints() != null ? req.estimatePoints() : commit.getEstimatePoints());
		item.setRcdoNodeId(req.rcdoNodeId() != null ? req.rcdoNodeId() : commit.getRcdoNodeId());
		item.setTargetWeekStartDate(
				req.targetWeekStartDate() != null ? req.targetWeekStartDate() : plan.getWeekStartDate());

		WorkItem saved = workItemRepo.save(item);
		if (semanticIndexService != null) {
			semanticIndexService.indexEntity(com.weeklycommit.ai.rag.SemanticIndexService.TYPE_TICKET, saved.getId());
		}
		return getTicketDetail(saved.getId());
	}

	// -------------------------------------------------------------------------
	// Read
	// -------------------------------------------------------------------------

	@Transactional(readOnly = true)
	public TicketDetailResponse getTicketDetail(UUID id) {
		WorkItem ticket = requireTicket(id);
		TicketResponse base = TicketResponse.from(ticket);

		List<TicketStatusHistoryResponse> statusHistory = historyRepo.findByWorkItemIdOrderByCreatedAtAsc(id).stream()
				.map(TicketStatusHistoryResponse::from).toList();

		List<LinkedCommitEntry> linkedCommits = commitRepo.findByWorkItemId(id).stream().map(commit -> {
			WeeklyPlan plan = planRepo.findById(commit.getPlanId()).orElse(null);
			if (plan == null) {
				return null;
			}
			return new LinkedCommitEntry(commit.getId(), commit.getPlanId(), commit.getTitle(), commit.getChessPiece(),
					commit.getEstimatePoints(), plan.getWeekStartDate(), commit.getOutcome());
		}).filter(java.util.Objects::nonNull).toList();

		return TicketDetailResponse.from(base, statusHistory, linkedCommits);
	}

	@Transactional(readOnly = true)
	public PagedTicketResponse listTickets(TicketListParams params) {
		Specification<WorkItem> spec = buildSpecification(params);
		Pageable pageable = PageRequest.of(params.normalizedPage() - 1, params.normalizedPageSize(),
				buildSort(params.normalizedSortBy(), params.normalizedSortDir()));
		Page<WorkItem> page = workItemRepo.findAll(spec, pageable);
		return new PagedTicketResponse(page.getContent().stream().map(TicketSummaryResponse::from).toList(),
				page.getTotalElements(), params.normalizedPage(), params.normalizedPageSize());
	}

	@Transactional(readOnly = true)
	public List<TicketSummaryResponse> listTicketSummaries(UUID teamId) {
		Specification<WorkItem> spec = (root, query,
				cb) -> teamId == null ? cb.conjunction() : cb.equal(root.get("teamId"), teamId);
		return workItemRepo.findAll(spec, Sort.by(Sort.Direction.DESC, "updatedAt")).stream()
				.map(TicketSummaryResponse::from).toList();
	}

	// -------------------------------------------------------------------------
	// Update
	// -------------------------------------------------------------------------

	public TicketDetailResponse updateTicket(UUID id, UpdateTicketRequest req, UUID actorUserId) {
		WorkItem item = requireTicket(id);

		if (req.title() != null && !req.title().isBlank()) {
			item.setTitle(req.title());
		}
		if (req.description() != null) {
			item.setDescription(req.description());
		}
		if (req.priority() != null) {
			item.setPriority(req.priority());
		}
		if (req.assigneeUserId() != null) {
			item.setAssigneeUserId(req.assigneeUserId());
		}
		if (req.teamId() != null) {
			item.setTeamId(req.teamId());
		}
		if (req.estimatePoints() != null) {
			validateEstimatePoints(req.estimatePoints());
			item.setEstimatePoints(req.estimatePoints());
		}
		if (req.rcdoNodeId() != null) {
			item.setRcdoNodeId(req.rcdoNodeId());
		}
		if (req.targetWeekStartDate() != null) {
			item.setTargetWeekStartDate(req.targetWeekStartDate());
		}
		if (req.status() != null) {
			transitionStatus(item, req.status(), actorUserId != null ? actorUserId : item.getReporterUserId());
		}

		workItemRepo.save(item);
		if (semanticIndexService != null) {
			semanticIndexService.indexEntity(com.weeklycommit.ai.rag.SemanticIndexService.TYPE_TICKET, item.getId());
		}
		return getTicketDetail(item.getId());
	}

	// -------------------------------------------------------------------------
	// Update status
	// -------------------------------------------------------------------------

	public TicketDetailResponse updateStatus(UUID id, TicketStatus newStatus, UUID changedByUserId) {
		WorkItem item = requireTicket(id);
		transitionStatus(item, newStatus, changedByUserId);
		workItemRepo.save(item);

		// Notify commit owner(s) when a ticket linked to a King or Queen commit is
		// blocked
		if (newStatus == TicketStatus.BLOCKED) {
			try {
				notifyCriticalTicketBlocked(item);
			} catch (Exception ex) {
				log.warn("Failed to send CRITICAL_TICKET_BLOCKED notification for ticket {}: {}", id, ex.getMessage());
			}
		}

		return getTicketDetail(item.getId());
	}

	/**
	 * Sends a CRITICAL_TICKET_BLOCKED notification to the owner of any King or
	 * Queen commit linked to this ticket.
	 */
	private void notifyCriticalTicketBlocked(WorkItem ticket) {
		List<WeeklyCommit> linkedCommits = commitRepo.findByWorkItemId(ticket.getId());
		for (WeeklyCommit commit : linkedCommits) {
			if (commit.getChessPiece() == ChessPiece.KING || commit.getChessPiece() == ChessPiece.QUEEN) {
				notificationService.createNotification(commit.getOwnerUserId(),
						NotificationEvent.CRITICAL_TICKET_BLOCKED, "Blocked ticket linked to " + commit.getChessPiece(),
						"Ticket \"" + ticket.getTitle() + "\" is now BLOCKED and is linked to your "
								+ commit.getChessPiece() + " commit \"" + commit.getTitle() + "\".",
						ticket.getId(), "TICKET");
			}
		}
	}

	// -------------------------------------------------------------------------
	// Status history
	// -------------------------------------------------------------------------

	@Transactional(readOnly = true)
	public List<TicketStatusHistoryResponse> getStatusHistory(UUID id) {
		requireTicket(id);
		return historyRepo.findByWorkItemIdOrderByCreatedAtAsc(id).stream().map(TicketStatusHistoryResponse::from)
				.toList();
	}

	// -------------------------------------------------------------------------
	// Delete
	// -------------------------------------------------------------------------

	public void deleteTicket(UUID id) {
		WorkItem item = requireTicket(id);
		workItemRepo.delete(item);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	WorkItem requireTicket(UUID id) {
		return workItemRepo.findById(id).orElseThrow(() -> new ResourceNotFoundException("Ticket not found: " + id));
	}

	private WeeklyCommit requireCommit(UUID id) {
		return commitRepo.findById(id).orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + id));
	}

	private WeeklyPlan requirePlan(UUID id) {
		return planRepo.findById(id).orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + id));
	}

	private void transitionStatus(WorkItem item, TicketStatus newStatus, UUID changedByUserId) {
		TicketStatus currentStatus = item.getStatus();
		if (currentStatus == newStatus) {
			return;
		}

		Set<TicketStatus> allowed = ALLOWED_TRANSITIONS.getOrDefault(currentStatus, EnumSet.noneOf(TicketStatus.class));
		if (!allowed.contains(newStatus)) {
			throw new PlanValidationException(
					"Illegal ticket status transition: " + currentStatus + " → " + newStatus + ". Allowed: " + allowed);
		}

		WorkItemStatusHistory history = new WorkItemStatusHistory();
		history.setWorkItemId(item.getId());
		history.setFromStatus(currentStatus != null ? currentStatus.name() : null);
		history.setToStatus(newStatus.name());
		history.setChangedByUserId(changedByUserId);
		historyRepo.save(history);

		item.setStatus(newStatus);
	}

	/**
	 * Generates a unique key for a ticket within its team.
	 */
	private String generateKey(UUID teamId) {
		long count = workItemRepo.countByTeamId(teamId);
		return KEY_PREFIX + (count + 1);
	}

	private Specification<WorkItem> buildSpecification(TicketListParams params) {
		return Specification.where(equalsUuid("assigneeUserId", params.assigneeUserId()))
				.and(equalsUuid("teamId", params.teamId())).and(equalsUuid("rcdoNodeId", params.rcdoNodeId()))
				.and(equalsEnum("status", params.status())).and(equalsEnum("priority", params.priority()))
				.and(equalsValue("targetWeekStartDate", params.targetWeek()));
	}

	private static <T> Specification<WorkItem> equalsValue(String field, T value) {
		return (root, query, cb) -> value == null ? cb.conjunction() : cb.equal(root.get(field), value);
	}

	private static Specification<WorkItem> equalsUuid(String field, UUID value) {
		return equalsValue(field, value);
	}

	private static <T extends Enum<T>> Specification<WorkItem> equalsEnum(String field, T value) {
		return equalsValue(field, value);
	}

	private Sort buildSort(String sortBy, String sortDir) {
		Sort.Direction direction = "asc".equalsIgnoreCase(sortDir) ? Sort.Direction.ASC : Sort.Direction.DESC;
		String property = switch (sortBy) {
			case "key" -> "key";
			case "title" -> "title";
			case "status" -> "status";
			case "priority" -> "priority";
			case "updatedAt" -> "updatedAt";
			default -> "updatedAt";
		};
		return Sort.by(direction, property);
	}

	static void validateEstimatePoints(Integer points) {
		if (points != null && !VALID_ESTIMATE_POINTS.contains(points)) {
			throw new PlanValidationException("Estimate points must be one of {1, 2, 3, 5, 8}, got: " + points);
		}
	}
}

package com.weeklycommit.lock.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.service.RiskDetectionService;
import com.weeklycommit.audit.service.AuditLogService;
import com.weeklycommit.domain.entity.LockSnapshotCommit;
import com.weeklycommit.domain.entity.LockSnapshotHeader;
import com.weeklycommit.domain.entity.RcdoNode;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.NotificationEvent;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.repository.LockSnapshotCommitRepository;
import com.weeklycommit.domain.repository.LockSnapshotHeaderRepository;
import com.weeklycommit.domain.repository.RcdoNodeRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.lock.dto.LockResponse;
import com.weeklycommit.lock.dto.LockSnapshotHeaderResponse;
import com.weeklycommit.lock.dto.ValidationError;
import com.weeklycommit.notification.service.NotificationService;
import com.weeklycommit.plan.dto.CommitResponse;
import com.weeklycommit.plan.dto.PlanResponse;
import com.weeklycommit.plan.dto.PlanWithCommitsResponse;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.report.service.ReadModelRefreshService;
import java.time.Instant;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class LockService {

	private static final Logger log = LoggerFactory.getLogger(LockService.class);

	private static final int MAX_KING_PER_WEEK = 1;
	private static final int MAX_QUEEN_PER_WEEK = 2;
	private static final java.util.Set<Integer> VALID_ESTIMATE_POINTS = java.util.Set.of(1, 2, 3, 5, 8);

	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final LockSnapshotHeaderRepository headerRepo;
	private final LockSnapshotCommitRepository commitSnapshotRepo;
	private final RcdoNodeRepository rcdoNodeRepo;
	private final ObjectMapper objectMapper;
	private final NotificationService notificationService;
	private final RiskDetectionService riskDetectionService;
	private final ReadModelRefreshService readModelRefreshService;
	private final AuditLogService auditLogService;

	/** Optional — injected when the RAG module is active; null-safe throughout. */
	@Autowired(required = false)
	private com.weeklycommit.ai.rag.SemanticIndexService semanticIndexService;

	/**
	 * Optional — injected in step-7 when InsightGenerationService is available;
	 * null-safe throughout.
	 */
	@Autowired(required = false)
	private com.weeklycommit.ai.rag.InsightGenerationService insightGenerationService;

	public LockService(WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo,
			LockSnapshotHeaderRepository headerRepo, LockSnapshotCommitRepository commitSnapshotRepo,
			RcdoNodeRepository rcdoNodeRepo, ObjectMapper objectMapper, NotificationService notificationService,
			RiskDetectionService riskDetectionService, ReadModelRefreshService readModelRefreshService,
			AuditLogService auditLogService) {
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.headerRepo = headerRepo;
		this.commitSnapshotRepo = commitSnapshotRepo;
		this.rcdoNodeRepo = rcdoNodeRepo;
		this.objectMapper = objectMapper;
		this.notificationService = notificationService;
		this.riskDetectionService = riskDetectionService;
		this.readModelRefreshService = readModelRefreshService;
		this.auditLogService = auditLogService;
	}

	// -------------------------------------------------------------------------
	// Manual lock
	// -------------------------------------------------------------------------

	/**
	 * Attempts to manually lock a DRAFT plan.
	 *
	 * <ul>
	 * <li>If the plan is already LOCKED the call is idempotent and returns
	 * success.</li>
	 * <li>If the plan is in any other non-DRAFT state a
	 * {@link PlanValidationException} is thrown (400).</li>
	 * <li>If hard validation fails the plan is <em>not</em> locked and the response
	 * contains the error list.</li>
	 * <li>On success the state transitions to LOCKED and a baseline snapshot is
	 * captured in the same transaction.</li>
	 * </ul>
	 */
	public LockResponse lockPlan(UUID planId, UUID actorUserId) {
		WeeklyPlan plan = findPlan(planId);

		if (plan.getState() == PlanState.LOCKED) {
			// Idempotent: already locked
			return LockResponse.success(buildPlanResponse(plan));
		}

		if (plan.getState() != PlanState.DRAFT) {
			throw new PlanValidationException("Plan " + planId + " cannot be locked from state " + plan.getState());
		}

		List<ValidationError> errors = validateForLock(plan);
		if (!errors.isEmpty()) {
			return LockResponse.validationFailed(errors);
		}

		// Compliance: on-time if locked before or at the deadline
		boolean onTime = !Instant.now().isAfter(plan.getLockDeadline());
		plan.setCompliant(onTime);
		plan.setState(PlanState.LOCKED);
		plan.setSystemLockedWithErrors(false);
		planRepo.save(plan);

		captureSnapshot(plan, false, List.of());
		triggerRiskDetection(plan.getId());
		triggerReadModelRefresh(plan.getId());

		auditLogService.record(AuditLogService.PLAN_LOCKED, actorUserId, "IC", AuditLogService.TARGET_PLAN, planId,
				null, Map.of("state", "LOCKED", "onTime", onTime));
		if (semanticIndexService != null) {
			semanticIndexService.indexEntity(com.weeklycommit.ai.rag.SemanticIndexService.TYPE_PLAN_SUMMARY,
					plan.getId());
		}
		if (insightGenerationService != null) {
			insightGenerationService.generatePersonalInsightsAsync(plan.getId());
		}

		return LockResponse.success(buildPlanResponse(plan));
	}

	// -------------------------------------------------------------------------
	// Auto-lock (called by scheduled job, idempotent)
	// -------------------------------------------------------------------------

	/**
	 * Locks an expired DRAFT plan as a system action. If the plan has validation
	 * errors the lock still proceeds but {@code system_locked_with_errors} is set.
	 *
	 * <p>
	 * After locking, an {@code AUTO_LOCK_OCCURRED} notification is sent to the plan
	 * owner and a {@code MANAGER_EXCEPTION_DIGEST} notification is sent to the
	 * team's manager (if one exists).
	 */
	public void autoLockPlan(UUID planId) {
		WeeklyPlan plan = planRepo.findById(planId).orElse(null);
		if (plan == null || plan.getState() != PlanState.DRAFT) {
			return; // idempotent: nothing to do
		}

		List<ValidationError> errors = validateForLock(plan);

		plan.setState(PlanState.LOCKED);
		plan.setCompliant(false); // auto-lock is never manually compliant
		plan.setSystemLockedWithErrors(!errors.isEmpty());
		planRepo.save(plan);

		captureSnapshot(plan, true, errors);
		triggerRiskDetection(plan.getId());
		triggerReadModelRefresh(plan.getId());

		auditLogService.recordSystem(AuditLogService.PLAN_AUTO_LOCKED, AuditLogService.TARGET_PLAN, planId, null,
				Map.of("state", "LOCKED", "systemLockedWithErrors", !errors.isEmpty(), "ownerUserId",
						plan.getOwnerUserId().toString()));

		// Notification hooks — fire-and-forget: failures must not roll back the lock
		try {
			notificationService.createNotification(plan.getOwnerUserId(), NotificationEvent.AUTO_LOCK_OCCURRED,
					"Plan auto-locked",
					"Your weekly plan for " + plan.getWeekStartDate() + " was automatically locked by the system.",
					plan.getId(), "PLAN");

			notificationService.findManagerForTeam(plan.getTeamId())
					.ifPresent(
							managerId -> notificationService.createNotification(managerId,
									NotificationEvent.MANAGER_EXCEPTION_DIGEST, "Auto-lock on team plan",
									"A plan for week " + plan.getWeekStartDate() + " in your team was auto-locked"
											+ (errors.isEmpty() ? "." : " with validation errors."),
									plan.getId(), "PLAN"));
		} catch (Exception ex) {
			log.warn("Failed to send auto-lock notifications for plan {}: {}", planId, ex.getMessage());
		}
	}

	// -------------------------------------------------------------------------
	// Snapshot retrieval
	// -------------------------------------------------------------------------

	@Transactional(readOnly = true)
	public LockSnapshotHeaderResponse getLockSnapshot(UUID planId) {
		LockSnapshotHeader header = headerRepo.findByPlanId(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Lock snapshot not found for plan: " + planId));
		return LockSnapshotHeaderResponse.from(header);
	}

	// -------------------------------------------------------------------------
	// Hard validation
	// -------------------------------------------------------------------------

	/** Returns the list of hard-validation errors. Empty means valid. */
	List<ValidationError> validateForLock(WeeklyPlan plan) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());

		List<ValidationError> errors = new ArrayList<>();

		if (commits.isEmpty()) {
			errors.add(ValidationError.of("commits", "At least one commit is required to lock the plan"));
			return errors; // no point validating individual commits
		}

		int kingCount = 0;
		int queenCount = 0;

		for (WeeklyCommit commit : commits) {
			String prefix = "commit[" + commit.getId() + "]";

			if (commit.getTitle() == null || commit.getTitle().isBlank()) {
				errors.add(ValidationError.of(prefix + ".title", "Title is required"));
			}
			if (commit.getChessPiece() == null) {
				errors.add(ValidationError.of(prefix + ".chessPiece", "Chess piece is required"));
				continue; // skip piece-dependent checks
			}
			if (commit.getPriorityOrder() < 1) {
				errors.add(ValidationError.of(prefix + ".priorityOrder", "Priority order must be ≥ 1"));
			}
			if (commit.getRcdoNodeId() == null) {
				errors.add(ValidationError.of(prefix + ".rcdoNodeId", "Primary RCDO link is required at lock time"));
			}
			if (commit.getEstimatePoints() == null) {
				errors.add(ValidationError.of(prefix + ".estimatePoints", "Estimate points are required at lock time"));
			} else if (!VALID_ESTIMATE_POINTS.contains(commit.getEstimatePoints())) {
				errors.add(ValidationError.of(prefix + ".estimatePoints",
						"Estimate points must be one of {1, 2, 3, 5, 8}"));
			}
			if ((commit.getChessPiece() == ChessPiece.KING || commit.getChessPiece() == ChessPiece.QUEEN)
					&& (commit.getSuccessCriteria() == null || commit.getSuccessCriteria().isBlank())) {
				errors.add(ValidationError.of(prefix + ".successCriteria",
						"Success criteria required for " + commit.getChessPiece() + " commits"));
			}
			if (commit.getChessPiece() == ChessPiece.KING)
				kingCount++;
			if (commit.getChessPiece() == ChessPiece.QUEEN)
				queenCount++;
		}

		if (kingCount > MAX_KING_PER_WEEK) {
			errors.add(ValidationError.of("commits.king", "Maximum 1 King commit per week; found " + kingCount));
		}
		if (queenCount > MAX_QUEEN_PER_WEEK) {
			errors.add(ValidationError.of("commits.queen", "Maximum 2 Queen commits per week; found " + queenCount));
		}

		return errors;
	}

	// -------------------------------------------------------------------------
	// Snapshot creation (called within existing transaction)
	// -------------------------------------------------------------------------

	private void triggerRiskDetection(UUID planId) {
		try {
			riskDetectionService.detectAndStoreRiskSignalsById(planId);
		} catch (Exception ex) {
			log.warn("Failed to compute risk signals for plan {}: {}", planId, ex.getMessage());
		}
	}

	private void triggerReadModelRefresh(UUID planId) {
		try {
			readModelRefreshService.refreshForPlan(planId);
		} catch (Exception ex) {
			log.warn("Failed to refresh read models for plan {}: {}", planId, ex.getMessage());
		}
	}

	/**
	 * Creates an immutable lock snapshot. Throws if a snapshot already exists for
	 * this plan (write-once enforcement).
	 */
	private void captureSnapshot(WeeklyPlan plan, boolean bySystem, List<ValidationError> validationErrors) {
		// Immutability guard: snapshot is write-once per plan
		if (headerRepo.findByPlanId(plan.getId()).isPresent()) {
			throw new PlanValidationException(
					"Lock snapshot already exists for plan " + plan.getId() + " — snapshots are immutable");
		}

		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());

		String payload = buildSnapshotPayload(plan, commits, validationErrors);

		LockSnapshotHeader header = new LockSnapshotHeader();
		header.setPlanId(plan.getId());
		header.setLockedBySystem(bySystem);
		header.setSnapshotPayload(payload);
		LockSnapshotHeader saved = headerRepo.save(header);

		for (WeeklyCommit commit : commits) {
			LockSnapshotCommit sc = new LockSnapshotCommit();
			sc.setSnapshotId(saved.getId());
			sc.setCommitId(commit.getId());
			sc.setSnapshotData(buildCommitSnapshot(commit));
			commitSnapshotRepo.save(sc);
		}

		// Back-reference on plan
		plan.setLockSnapshotId(saved.getId());
		planRepo.save(plan);
	}

	// -------------------------------------------------------------------------
	// JSON snapshot builders
	// -------------------------------------------------------------------------

	private String buildSnapshotPayload(WeeklyPlan plan, List<WeeklyCommit> commits,
			List<ValidationError> validationErrors) {
		Map<String, Object> m = new LinkedHashMap<>();
		m.put("planId", str(plan.getId()));
		m.put("ownerUserId", str(plan.getOwnerUserId()));
		m.put("teamId", str(plan.getTeamId()));
		m.put("weekStartDate", plan.getWeekStartDate().toString());
		m.put("capacityBudgetPoints", plan.getCapacityBudgetPoints());
		m.put("lockedAt", Instant.now().toString());
		m.put("commits", commits.stream().map(this::buildCommitSnapshotMap).toList());
		if (!validationErrors.isEmpty()) {
			m.put("validationErrors", validationErrors);
		}
		return toJson(m);
	}

	private String buildCommitSnapshot(WeeklyCommit commit) {
		return toJson(buildCommitSnapshotMap(commit));
	}

	private Map<String, Object> buildCommitSnapshotMap(WeeklyCommit commit) {
		Map<String, Object> m = new LinkedHashMap<>();
		m.put("id", str(commit.getId()));
		m.put("title", commit.getTitle());
		m.put("chessPiece", commit.getChessPiece() != null ? commit.getChessPiece().name() : null);
		m.put("priorityOrder", commit.getPriorityOrder());
		m.put("estimatePoints", commit.getEstimatePoints());
		m.put("successCriteria", commit.getSuccessCriteria());
		m.put("description", commit.getDescription());
		m.put("rcdoNodeId", str(commit.getRcdoNodeId()));
		m.put("workItemId", str(commit.getWorkItemId()));
		m.put("rcdoPath", buildRcdoPath(commit.getRcdoNodeId()));
		return m;
	}

	private List<Map<String, Object>> buildRcdoPath(UUID nodeId) {
		if (nodeId == null)
			return List.of();
		List<Map<String, Object>> path = new ArrayList<>();
		UUID current = nodeId;
		while (current != null) {
			RcdoNode node = rcdoNodeRepo.findById(current).orElse(null);
			if (node == null)
				break;
			Map<String, Object> entry = new LinkedHashMap<>();
			entry.put("id", str(node.getId()));
			entry.put("nodeType", node.getNodeType().name());
			entry.put("title", node.getTitle());
			entry.put("status", node.getStatus().name());
			path.add(0, entry); // root first
			current = node.getParentId();
		}
		return path;
	}

	// -------------------------------------------------------------------------
	// Helpers
	// -------------------------------------------------------------------------

	private WeeklyPlan findPlan(UUID planId) {
		return planRepo.findById(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + planId));
	}

	private PlanWithCommitsResponse buildPlanResponse(WeeklyPlan plan) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());
		int total = commits.stream().mapToInt(c -> c.getEstimatePoints() != null ? c.getEstimatePoints() : 0).sum();
		return new PlanWithCommitsResponse(PlanResponse.from(plan), commits.stream().map(CommitResponse::from).toList(),
				total);
	}

	private String toJson(Object obj) {
		try {
			return objectMapper.writeValueAsString(obj);
		} catch (JsonProcessingException e) {
			throw new IllegalStateException("Failed to serialize snapshot payload", e);
		}
	}

	private static String str(UUID id) {
		return id != null ? id.toString() : null;
	}
}

