import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

/**
 * Handles semantic (RAG) queries: embeds the question, retrieves relevant
 * chunks from Pinecone, and synthesises an answer via the LLM.
 *
 * <p>
 * Pipeline:
 * <ol>
 * <li>Intent classification — extracts entity-type filters and time-range from
 * the natural-language question.</li>
 * <li>Embedding — converts the question to a dense vector.</li>
 * <li>Pinecone retrieval — nearest-neighbour search with metadata filters.</li>
 * <li>Answer generation — packs retrieved chunks into a RAG prompt and calls
 * the LLM.</li>
 * <li>Audit — persists the interaction via {@link AiSuggestionService}.</li>
 * </ol>
 *
 * <p>
 * All steps degrade gracefully: if any upstream service is unavailable, the
 * method returns an unavailable {@link RagQueryResult} without throwing.
 */
@Service
public class SemanticQueryService {

	private static final Logger log = LoggerFactory.getLogger(SemanticQueryService.class);
	private static final int TOP_K = 5;

	// ── Inner records ─────────────────────────────────────────────────────

	/**
	 * A single source item that contributed to a RAG answer.
	 *
	 * @param entityType
	 *            e.g. {@code "commit"}, {@code "plan_summary"}
	 * @param entityId
	 *            the entity UUID string
	 * @param weekStartDate
	 *            ISO week-start date extracted from vector metadata (may be empty)
	 * @param snippet
	 *            brief excerpt from the chunk text
	 */
	public record RagSource(String entityType, String entityId, String weekStartDate, String snippet) {
	}

	/**
	 * Result of a RAG query.
	 *
	 * @param available
	 *            {@code false} if any upstream dependency is unavailable
	 * @param answer
	 *            synthesised natural-language answer (null when unavailable)
	 * @param sources
	 *            retrieved chunks that informed the answer
	 * @param confidence
	 *            model confidence [0.0, 1.0]
	 * @param suggestionId
	 *            ID of the persisted
	 *            {@link com.weeklycommit.domain.entity.AiSuggestion} audit record
	 *            (null when unavailable)
	 */
	public record RagQueryResult(boolean available, String answer, List<RagSource> sources, double confidence,
			UUID suggestionId) {

		/** Convenience factory for a degraded/unavailable result. */
		public static RagQueryResult unavailable() {
			return new RagQueryResult(false, null, List.of(), 0.0, null);
		}
	}

	// ── Dependencies ──────────────────────────────────────────────────────

	private final PineconeClient pineconeClient;
	private final EmbeddingService embeddingService;
	private final AiProviderRegistry aiProviderRegistry;
	private final AiSuggestionService aiSuggestionService;
	private final ObjectMapper objectMapper;
	private final TeamRepository teamRepo;

	public SemanticQueryService(PineconeClient pineconeClient, EmbeddingService embeddingService,
			AiProviderRegistry aiProviderRegistry, AiSuggestionService aiSuggestionService, ObjectMapper objectMapper,
			TeamRepository teamRepo) {
		this.pineconeClient = pineconeClient;
		this.embeddingService = embeddingService;
		this.aiProviderRegistry = aiProviderRegistry;
		this.aiSuggestionService = aiSuggestionService;
		this.objectMapper = objectMapper;
		this.teamRepo = teamRepo;
	}

	// ── Public API ────────────────────────────────────────────────────────

	/**
	 * Executes a RAG query for the given question scoped to a team.
	 *
	 * @param question
	 *            natural-language question from the user
	 * @param teamId
	 *            team scope for Pinecone namespace + metadata filter
	 * @param userId
	 *            requesting user (for audit)
	 * @return query result, never {@code null}; check
	 *         {@link RagQueryResult#available()}
	 */
	public RagQueryResult query(String question, UUID teamId, UUID userId) {
		if (!pineconeClient.isAvailable() || !embeddingService.isAvailable()) {
			log.debug("SemanticQueryService: unavailable (pinecone={}, embedding={})", pineconeClient.isAvailable(),
					embeddingService.isAvailable());
			return RagQueryResult.unavailable();
		}
		if (question == null || question.isBlank()) {
			return RagQueryResult.unavailable();
		}

		try {
			// Step 2: intent classification
			IntentResult intent = classifyIntent(question, teamId, userId);

			// Step 3: embed the question
			float[] vector = embeddingService.embed(question);
			if (vector.length == 0) {
				log.debug("SemanticQueryService: embedding returned empty vector — unavailable");
				return RagQueryResult.unavailable();
			}

			// Step 4: build metadata filter
			Map<String, Object> filter = buildFilter(intent, teamId);

			// Step 5: query Pinecone
			String namespace = resolveNamespace(teamId);
			List<PineconeClient.PineconeMatch> matches = pineconeClient.query(namespace, vector, TOP_K, filter);

			// Step 6 & 7: build RAG prompt context and generate answer
			String contextString = buildContextString(question, matches);
			AiContext ragContext = new AiContext(AiContext.TYPE_RAG_QUERY, userId, null, null, Map.of(), Map.of(),
					List.of(), List.of(), buildRagAdditionalContext(question, matches));
			AiSuggestionResult llmResult = aiProviderRegistry.generateSuggestion(ragContext);

			// Step 7: parse the answer
			RagAnswer ragAnswer = parseRagAnswer(llmResult);

			// Step 8: persist audit record
			com.weeklycommit.domain.entity.AiSuggestion stored = null;
			try {
				stored = aiSuggestionService.storeSuggestion(AiContext.TYPE_RAG_QUERY, userId, null, null,
						contextString, llmResult);
			} catch (Exception ex) {
				log.warn("SemanticQueryService: failed to store suggestion audit record — {}", ex.getMessage());
			}

			// Step 9: return result
			UUID suggestionId = stored != null ? stored.getId() : null;
			return new RagQueryResult(true, ragAnswer.answer(), ragAnswer.sources(), ragAnswer.confidence(),
					suggestionId);

		} catch (Exception e) {
			log.warn("SemanticQueryService: query failed — {}", e.getMessage());
			return RagQueryResult.unavailable();
		}
	}

	// ── Private pipeline steps ────────────────────────────────────────────

	/**
	 * Calls the LLM for intent classification. Returns safe defaults if the LLM
	 * call fails or returns unparseable JSON.
	 */
	private IntentResult classifyIntent(String question, UUID teamId, UUID userId) {
		try {
			Map<String, Object> additionalCtx = Map.of("question", question, "teamId",
					teamId != null ? teamId.toString() : "");
			AiContext intentContext = new AiContext(AiContext.TYPE_RAG_INTENT, userId, null, null, Map.of(), Map.of(),
					List.of(), List.of(), additionalCtx);
			AiSuggestionResult result = aiProviderRegistry.generateSuggestion(intentContext);
			if (!result.available()) {
				return IntentResult.defaults();
			}
			return parseIntentResult(result.payload());
		} catch (Exception e) {
			log.debug("SemanticQueryService: intent classification failed — {}", e.getMessage());
			return IntentResult.defaults();
		}
	}

	private IntentResult parseIntentResult(String payload) {
		try {
			JsonNode root = objectMapper.readTree(payload);
			List<String> entityTypes = new ArrayList<>();
			JsonNode et = root.path("entityTypes");
			if (et.isArray()) {
				for (JsonNode node : et) {
					entityTypes.add(node.asText());
				}
			}
			String from = root.path("timeRange").path("from").asText(null);
			String to = root.path("timeRange").path("to").asText(null);
			return new IntentResult(entityTypes, from, to);
		} catch (Exception e) {
			log.debug("SemanticQueryService: could not parse intent — using defaults");
			return IntentResult.defaults();
		}
	}

	private Map<String, Object> buildFilter(IntentResult intent, UUID teamId) {
		Map<String, Object> filter = new HashMap<>();
		if (teamId != null) {
			filter.put("teamId", teamId.toString());
		}
		// Entity type filter is advisory — only add when LLM provided specific types
		if (intent.entityTypes() != null && !intent.entityTypes().isEmpty()) {
			// Pinecone $in operator for multi-value filter
			filter.put("entityType", Map.of("$in", intent.entityTypes()));
		}
		return filter.isEmpty() ? null : filter;
	}

	private String resolveNamespace(UUID teamId) {
		if (teamId == null) {
			return "";
		}
		return teamRepo.findById(teamId).map(Team::getOrganizationId)
				.map(orgId -> orgId != null ? orgId.toString() : "").orElse("");
	}

	private String buildContextString(String question, List<PineconeClient.PineconeMatch> matches) {
		try {
			Map<String, Object> ctx = new HashMap<>();
			ctx.put("question", question);
			ctx.put("retrievedChunks", matches.size());
			return objectMapper.writeValueAsString(ctx);
		} catch (Exception e) {
			return "{\"question\":\"" + question + "\"}";
		}
	}

	private Map<String, Object> buildRagAdditionalContext(String question, List<PineconeClient.PineconeMatch> matches) {
		List<Map<String, Object>> chunks = matches.stream().map(m -> {
			Map<String, Object> chunk = new HashMap<>();
			chunk.put("id", m.id());
			chunk.put("score", m.score());
			chunk.put("metadata", m.metadata());
			return chunk;
		}).toList();
		return Map.of("question", question, "retrievedChunks", chunks);
	}

	private RagAnswer parseRagAnswer(AiSuggestionResult result) {
		if (!result.available()) {
			return new RagAnswer("AI provider unavailable", List.of(), 0.0);
		}
		try {
			JsonNode root = objectMapper.readTree(result.payload());
			String answer = root.path("answer").asText("No answer generated");
			double confidence = root.path("confidence").asDouble(0.0);

			List<RagSource> sources = new ArrayList<>();
			JsonNode sourcesNode = root.path("sources");
			if (sourcesNode.isArray()) {
				for (JsonNode s : sourcesNode) {
					sources.add(new RagSource(s.path("entityType").asText(""), s.path("entityId").asText(""),
							s.path("weekStartDate").asText(""), s.path("snippet").asText("")));
				}
			}
			return new RagAnswer(answer, sources, confidence);
		} catch (Exception e) {
			log.debug("SemanticQueryService: could not parse RAG answer — {}", e.getMessage());
			return new RagAnswer(result.payload(), List.of(), result.confidence());
		}
	}

	// ── Private helper records ────────────────────────────────────────────

	private record IntentResult(List<String> entityTypes, String timeRangeFrom, String timeRangeTo) {

		static IntentResult defaults() {
			return new IntentResult(List.of(), null, null);
		}
	}

	private record RagAnswer(String answer, List<RagSource> sources, double confidence) {
	}
}

package com.weeklycommit.ai.rag;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyInt;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.ArgumentMatchers.isNull;
import static org.mockito.Mockito.never;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.ai.service.AiSuggestionService;
import com.weeklycommit.domain.entity.AiSuggestion;
import com.weeklycommit.domain.entity.Team;
import com.weeklycommit.domain.repository.TeamRepository;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.UUID;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.ArgumentCaptor;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

/**
 * Unit tests for {@link SemanticQueryService}.
 *
 * <p>
 * Mocks all upstream services so no real HTTP / DB calls are made.
 */
@ExtendWith(MockitoExtension.class)
class SemanticQueryServiceTest {

	private static final UUID TEAM_ID = UUID.randomUUID();
	private static final UUID USER_ID = UUID.randomUUID();
	private static final UUID ORG_ID = UUID.randomUUID();
	private static final String QUESTION = "What did the team commit to last week?";

	private final ObjectMapper objectMapper = new ObjectMapper();

	@Mock
	private PineconeClient pineconeClient;

	@Mock
	private EmbeddingService embeddingService;

	@Mock
	private AiProviderRegistry aiProviderRegistry;

	@Mock
	private AiSuggestionService aiSuggestionService;

	@Mock
	private TeamRepository teamRepo;

	private SemanticQueryService service;

	@BeforeEach
	void setUp() {
		service = new SemanticQueryService(pineconeClient, embeddingService, aiProviderRegistry, aiSuggestionService,
				objectMapper, teamRepo);
	}

	// ── Availability guards ───────────────────────────────────────────────

	@Test
	void query_pineconeUnavailable_returnsUnavailableResult() {
		when(pineconeClient.isAvailable()).thenReturn(false);

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isFalse();
		assertThat(result.answer()).isNull();
		verify(embeddingService, never()).embed(anyString());
	}

	@Test
	void query_embeddingUnavailable_returnsUnavailableResult() {
		when(pineconeClient.isAvailable()).thenReturn(true);
		when(embeddingService.isAvailable()).thenReturn(false);

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isFalse();
		verify(embeddingService, never()).embed(anyString());
	}

	@Test
	void query_nullQuestion_returnsUnavailableResult() {
		when(pineconeClient.isAvailable()).thenReturn(true);
		when(embeddingService.isAvailable()).thenReturn(true);

		SemanticQueryService.RagQueryResult result = service.query(null, TEAM_ID, USER_ID);

		assertThat(result.available()).isFalse();
	}

	@Test
	void query_blankQuestion_returnsUnavailableResult() {
		when(pineconeClient.isAvailable()).thenReturn(true);
		when(embeddingService.isAvailable()).thenReturn(true);

		SemanticQueryService.RagQueryResult result = service.query("   ", TEAM_ID, USER_ID);

		assertThat(result.available()).isFalse();
	}

	@Test
	void query_embeddingReturnsEmptyVector_returnsUnavailableResult() {
		when(pineconeClient.isAvailable()).thenReturn(true);
		when(embeddingService.isAvailable()).thenReturn(true);
		when(aiProviderRegistry.generateSuggestion(any())).thenReturn(AiSuggestionResult.unavailable());
		when(embeddingService.embed(anyString())).thenReturn(new float[0]);

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isFalse();
		verify(pineconeClient, never()).query(anyString(), any(), anyInt(), any());
	}

	// ── Successful pipeline ───────────────────────────────────────────────

	@Test
	void query_successfulPipeline_returnsAvailableResult() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		mockIntentResponse(intentPayload("status_query", List.of("commit")));
		float[] embedding = {0.1f, 0.2f, 0.3f};
		when(embeddingService.embed(QUESTION)).thenReturn(embedding);
		mockPineconeMatches(List.of("commit:uuid-1"), List.of(0.92));
		mockRagAnswer("The team committed to deploying the new API.", 0.9);
		stubSuggestionStore(UUID.randomUUID());

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isTrue();
		assertThat(result.answer()).isEqualTo("The team committed to deploying the new API.");
		assertThat(result.confidence()).isEqualTo(0.9);
		assertThat(result.suggestionId()).isNotNull();
	}

	@Test
	void query_successfulPipeline_returnsCorrectSources() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		mockIntentResponse(intentPayload("status_query", List.of("commit")));
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		mockPineconeMatches(List.of("commit:uuid-1"), List.of(0.92));
		String answerWithSource = """
				{
				  "answer": "Team committed to API work.",
				  "sources": [
				    {"entityType": "commit", "entityId": "uuid-1", "weekStartDate": "2025-01-06", "snippet": "Deploy new API"}
				  ],
				  "confidence": 0.85
				}
				""";
		when(aiProviderRegistry.generateSuggestion(argOfType(AiContext.TYPE_RAG_QUERY)))
				.thenReturn(new AiSuggestionResult(true, answerWithSource.trim(), "RAG answer", 0.85, "stub-v1"));
		stubSuggestionStore(UUID.randomUUID());

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.sources()).hasSize(1);
		assertThat(result.sources().get(0).entityType()).isEqualTo("commit");
		assertThat(result.sources().get(0).entityId()).isEqualTo("uuid-1");
		assertThat(result.sources().get(0).weekStartDate()).isEqualTo("2025-01-06");
	}

	// ── Intent failure degrades gracefully ────────────────────────────────

	@Test
	void query_intentClassificationFails_proceedsWithDefaults() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		// Intent returns unavailable
		when(aiProviderRegistry.generateSuggestion(argOfType(AiContext.TYPE_RAG_INTENT)))
				.thenReturn(AiSuggestionResult.unavailable());
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		mockPineconeMatches(List.of(), List.of());
		mockRagAnswer("No data found.", 0.3);
		stubSuggestionStore(UUID.randomUUID());

		// Should not throw; should proceed with empty filter defaults
		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		// Pinecone is still called (with default/empty filter)
		verify(pineconeClient).query(anyString(), any(), eq(5), any());
		assertThat(result.available()).isTrue();
	}

	@Test
	void query_intentPayloadUnparseable_proceedsWithDefaults() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		when(aiProviderRegistry.generateSuggestion(argOfType(AiContext.TYPE_RAG_INTENT)))
				.thenReturn(new AiSuggestionResult(true, "not-valid-json", "intent", 0.5, "stub"));
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		mockPineconeMatches(List.of(), List.of());
		mockRagAnswer("Answer.", 0.5);
		stubSuggestionStore(UUID.randomUUID());

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isTrue();
	}

	// ── Audit storage ─────────────────────────────────────────────────────

	@Test
	void query_successfulResult_storesSuggestionWithCorrectType() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		mockIntentResponse(intentPayload("status_query", List.of("commit")));
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		mockPineconeMatches(List.of(), List.of());
		mockRagAnswer("Answer.", 0.8);
		UUID suggestionId = UUID.randomUUID();
		stubSuggestionStore(suggestionId);

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		ArgumentCaptor<String> typeCaptor = ArgumentCaptor.forClass(String.class);
		verify(aiSuggestionService).storeSuggestion(typeCaptor.capture(), eq(USER_ID), isNull(), isNull(), anyString(),
				any(AiSuggestionResult.class));
		assertThat(typeCaptor.getValue()).isEqualTo(AiContext.TYPE_RAG_QUERY);
		assertThat(result.suggestionId()).isEqualTo(suggestionId);
	}

	@Test
	void query_suggestionStoreFails_stillReturnsResult() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		mockIntentResponse(intentPayload("status_query", List.of()));
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		mockPineconeMatches(List.of(), List.of());
		mockRagAnswer("Answer.", 0.7);
		when(aiSuggestionService.storeSuggestion(anyString(), any(), any(), any(), anyString(), any()))
				.thenThrow(new RuntimeException("DB error"));

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isTrue();
		assertThat(result.suggestionId()).isNull();
	}

	// ── Namespace resolution ──────────────────────────────────────────────

	@Test
	void query_usesOrgIdAsNamespace() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		mockIntentResponse(intentPayload("general_query", List.of()));
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		when(pineconeClient.query(anyString(), any(), anyInt(), any())).thenReturn(List.of());
		mockRagAnswer("Answer.", 0.5);
		stubSuggestionStore(UUID.randomUUID());

		service.query(QUESTION, TEAM_ID, USER_ID);

		ArgumentCaptor<String> namespaceCaptor = ArgumentCaptor.forClass(String.class);
		verify(pineconeClient).query(namespaceCaptor.capture(), any(), anyInt(), any());
		assertThat(namespaceCaptor.getValue()).isEqualTo(ORG_ID.toString());
	}

	// ── Helpers ───────────────────────────────────────────────────────────

	private void setUpAvailableServices() {
		when(pineconeClient.isAvailable()).thenReturn(true);
		when(embeddingService.isAvailable()).thenReturn(true);
	}

	private void setUpTeam() {
		Team team = new Team();
		team.setId(TEAM_ID);
		team.setOrganizationId(ORG_ID);
		when(teamRepo.findById(TEAM_ID)).thenReturn(Optional.of(team));
	}

	private void mockIntentResponse(String payload) {
		when(aiProviderRegistry.generateSuggestion(argOfType(AiContext.TYPE_RAG_INTENT)))
				.thenReturn(new AiSuggestionResult(true, payload, "intent", 0.9, "stub-v1"));
	}

	private void mockRagAnswer(String answer, double confidence) throws Exception {
		String payload = objectMapper
				.writeValueAsString(Map.of("answer", answer, "sources", List.of(), "confidence", confidence));
		when(aiProviderRegistry.generateSuggestion(argOfType(AiContext.TYPE_RAG_QUERY)))
				.thenReturn(new AiSuggestionResult(true, payload, "rag answer", confidence, "stub-v1"));
	}

	private void mockPineconeMatches(List<String> ids, List<Double> scores) {
		List<PineconeClient.PineconeMatch> matches = new java.util.ArrayList<>();
		for (int i = 0; i < ids.size(); i++) {
			matches.add(new PineconeClient.PineconeMatch(ids.get(i), scores.get(i), Map.of()));
		}
		when(pineconeClient.query(anyString(), any(), anyInt(), any())).thenReturn(matches);
	}

	private void stubSuggestionStore(UUID suggestionId) {
		AiSuggestion stored = new AiSuggestion();
		stored.setId(suggestionId);
		when(aiSuggestionService.storeSuggestion(anyString(), any(), any(), any(), anyString(), any()))
				.thenReturn(stored);
	}

	private static String intentPayload(String intent, List<String> entityTypes) throws Exception {
		return new ObjectMapper()
				.writeValueAsString(Map.of("intent", intent, "entityTypes", entityTypes, "keywords", List.of()));
	}

	/** Matches an AiContext by its suggestionType for Mockito. */
	private static AiContext argOfType(String type) {
		return org.mockito.ArgumentMatchers.argThat(ctx -> ctx != null && type.equals(ctx.suggestionType()));
	}
}

package com.weeklycommit.ai.provider;

import java.util.List;
import java.util.Map;
import java.util.UUID;

/**
 * Input context supplied to an {@link AiProvider} when requesting a suggestion.
 * All fields are optional except {@code suggestionType}.
 */
public record AiContext(
		/** Discriminator for the kind of suggestion being requested. */
		String suggestionType,
		/** Requesting user (for personalisation and audit). */
		UUID userId,
		/** Plan being analysed, if applicable. */
		UUID planId,
		/** Specific commit being analysed, if applicable. */
		UUID commitId,
		/** Serialised current commit fields (title, chessPiece, etc.). */
		Map<String, Object> commitData,
		/** Serialised plan summary (state, capacity, etc.). */
		Map<String, Object> planData,
		/** Recent historical commits for pattern matching. */
		List<Map<String, Object>> historicalCommits,
		/** Relevant RCDO tree nodes. */
		List<Map<String, Object>> rcdoTree,
		/** Free-form additional context (e.g., scope changes, risk inputs). */
		Map<String, Object> additionalContext) {

	/** Suggestion type constant — commit draft assistance. */
	public static final String TYPE_COMMIT_DRAFT = "COMMIT_DRAFT_ASSIST";

	/** Suggestion type constant — commit quality lint. */
	public static final String TYPE_COMMIT_LINT = "COMMIT_LINT";

	/** Suggestion type constant — RCDO link suggestion. */
	public static final String TYPE_RCDO_SUGGEST = "RCDO_SUGGEST";

	/** Suggestion type constant — risk signal detection. */
	public static final String TYPE_RISK_SIGNAL = "RISK_SIGNAL";

	/** Suggestion type constant — reconciliation assistance. */
	public static final String TYPE_RECONCILE_ASSIST = "RECONCILE_ASSIST";

	/** Suggestion type constant — team manager AI summary. */
	public static final String TYPE_TEAM_SUMMARY = "TEAM_SUMMARY";

	/** Suggestion type constant — RAG intent classification. */
	public static final String TYPE_RAG_INTENT = "RAG_INTENT";

	/** Suggestion type constant — RAG answer generation. */
	public static final String TYPE_RAG_QUERY = "RAG_QUERY";
}

package com.weeklycommit.ai.provider;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;

/**
 * Development/test stub implementation of {@link AiProvider}.
 *
 * <p>
 * Returns deterministic canned responses for every suggestion type so the rest
 * of the AI pipeline can be tested end-to-end without a real model. Always
 * reports itself as available.
 */
@Component
@org.springframework.boot.autoconfigure.condition.ConditionalOnProperty(name = "ai.provider", havingValue = "stub")
public class StubAiProvider implements AiProvider {

	private static final Logger log = LoggerFactory.getLogger(StubAiProvider.class);

	static final String STUB_MODEL_VERSION = "stub-v1";

	@Override
	public String getName() {
		return "stub";
	}

	@Override
	public String getVersion() {
		return STUB_MODEL_VERSION;
	}

	@Override
	public boolean isAvailable() {
		return true;
	}

	@Override
	public AiSuggestionResult generateSuggestion(AiContext context) {
		log.debug("StubAiProvider.generateSuggestion: type={}", context.suggestionType());
		String payload;
		String rationale;
		double confidence = 0.85;

		switch (context.suggestionType()) {
			case AiContext.TYPE_COMMIT_DRAFT -> {
				payload = """
						{
						  "suggestedTitle": "Implement feature with clear acceptance criteria",
						  "suggestedDescription": "Break this commit into smaller, measurable deliverables.",
						  "suggestedSuccessCriteria": "Feature is deployed and passing all tests.",
						  "suggestedEstimatePoints": 3
						}
						""";
				rationale = "Commit title appears vague; similar past commits used more specific language.";
			}
			case AiContext.TYPE_COMMIT_LINT -> {
				payload = """
						{
						  "hardValidation": [],
						  "softGuidance": [
						    {
						      "code": "VAGUE_TITLE",
						      "message": "Consider making the title more specific and outcome-focused."
						    }
						  ]
						}
						""";
				rationale = "Commit title could be more specific. No hard violations detected.";
				confidence = 0.9;
			}
			case AiContext.TYPE_RCDO_SUGGEST -> {
				Object rcdoList = context.rcdoTree() != null && !context.rcdoTree().isEmpty()
						? context.rcdoTree().get(0).get("id")
						: null;
				payload = String.format("""
						{
						  "suggestedRcdoNodeId": "%s",
						  "confidence": 0.85
						}
						""", rcdoList != null ? rcdoList : "");
				rationale = "Commit title and description closely match this Outcome's scope.";
				confidence = 0.85;
			}
			case AiContext.TYPE_RISK_SIGNAL -> {
				payload = """
						{
						  "signals": []
						}
						""";
				rationale = "No risk signals detected for this plan.";
				confidence = 0.95;
			}
			case AiContext.TYPE_RECONCILE_ASSIST -> {
				payload = """
						{
						  "likelyOutcomes": [],
						  "draftSummary": "Plan reconciliation appears straightforward with no major deviations.",
						  "carryForwardRecommendations": []
						}
						""";
				rationale = "No unresolved commits detected that require carry-forward.";
			}
			case AiContext.TYPE_TEAM_SUMMARY -> {
				payload = """
						{
						  "summaryText": "Team plan looks healthy this week.",
						  "topRcdoBranches": [],
						  "carryForwardPatterns": [],
						  "criticalBlockedItemIds": []
						}
						""";
				rationale = "Generated from team plan data for the requested week.";
			}
			case AiContext.TYPE_RAG_INTENT -> {
				payload = """
						{
						  "intent": "status_query",
						  "entityTypes": ["commit", "plan_summary"],
						  "timeRange": null,
						  "keywords": ["weekly", "commit", "plan"]
						}
						""";
				rationale = "Intent classified as a general status query over commits and plans.";
			}
			case AiContext.TYPE_RAG_QUERY -> {
				payload = """
						{
						  "answer": "Based on the retrieved planning data, the team is making steady progress.",
						  "sources": [],
						  "confidence": 0.85
						}
						""";
				rationale = "Answer generated from retrieved context chunks.";
			}
			default -> {
				payload = "{}";
				rationale = "Unknown suggestion type.";
				confidence = 0.0;
			}
		}

		return new AiSuggestionResult(true, payload.trim(), rationale, confidence, STUB_MODEL_VERSION);
	}
}

package com.weeklycommit.ai.provider;

import java.util.List;
import java.util.Optional;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;

/**
 * Manages registered {@link AiProvider} implementations and exposes the active
 * provider for the application.
 *
 * <p>
 * AI can be disabled globally via the {@code ai.enabled} property (default
 * {@code true}). When disabled, {@link #isAiEnabled()} returns {@code false}
 * and {@link #generateSuggestion(AiContext)} returns
 * {@link AiSuggestionResult#unavailable()} without calling any provider.
 *
 * <p>
 * Provider selection: the first registered provider that reports
 * {@link AiProvider#isAvailable()} is used. If none are available, the result
 * is also unavailable.
 */
@Component
public class AiProviderRegistry {

	private static final Logger log = LoggerFactory.getLogger(AiProviderRegistry.class);

	@Value("${ai.enabled:true}")
	private boolean aiEnabled;

	private final List<AiProvider> providers;

	public AiProviderRegistry(List<AiProvider> providers) {
		this.providers = providers != null ? providers : List.of();
	}

	/**
	 * Returns {@code true} when AI is enabled via feature flag AND at least one
	 * provider is registered.
	 */
	public boolean isAiEnabled() {
		return aiEnabled && !providers.isEmpty();
	}

	/**
	 * Returns the first registered provider that reports itself as available, or
	 * {@link Optional#empty()} if none are.
	 */
	public Optional<AiProvider> getActiveProvider() {
		if (!aiEnabled) {
			log.debug("AI is disabled via feature flag");
			return Optional.empty();
		}
		return providers.stream().filter(AiProvider::isAvailable).findFirst();
	}

	/**
	 * Convenience method: generates a suggestion using the active provider, or
	 * returns {@link AiSuggestionResult#unavailable()} with graceful degradation if
	 * the provider is unavailable or AI is disabled.
	 *
	 * <p>
	 * Core workflow is never affected — callers should check
	 * {@link AiSuggestionResult#available()} on the response.
	 *
	 * @param context
	 *            the input context
	 * @return suggestion result, never {@code null}
	 */
	public AiSuggestionResult generateSuggestion(AiContext context) {
		Optional<AiProvider> provider = getActiveProvider();
		if (provider.isEmpty()) {
			log.debug("No active AI provider; returning unavailable result for type={}", context.suggestionType());
			return AiSuggestionResult.unavailable();
		}
		try {
			return provider.get().generateSuggestion(context);
		} catch (Exception ex) {
			log.warn("AI provider threw exception for type={}: {}", context.suggestionType(), ex.getMessage());
			return AiSuggestionResult.unavailable();
		}
	}

	// Visible for testing
	boolean isAiEnabledFlag() {
		return aiEnabled;
	}

	void setAiEnabled(boolean aiEnabled) {
		this.aiEnabled = aiEnabled;
	}
}

package com.weeklycommit.ai.service;

import com.weeklycommit.ai.dto.AiFeedbackRequest;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.domain.entity.AiFeedback;
import com.weeklycommit.domain.entity.AiSuggestion;
import com.weeklycommit.domain.repository.AiFeedbackRepository;
import com.weeklycommit.domain.repository.AiSuggestionRepository;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.time.LocalDate;
import java.util.HexFormat;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Handles storage and retrieval of {@link AiSuggestion} records and
 * {@link AiFeedback} records.
 */
@Service
@Transactional
public class AiSuggestionService {

	private static final Logger log = LoggerFactory.getLogger(AiSuggestionService.class);

	private final AiSuggestionRepository suggestionRepo;
	private final AiFeedbackRepository feedbackRepo;

	public AiSuggestionService(AiSuggestionRepository suggestionRepo, AiFeedbackRepository feedbackRepo) {
		this.suggestionRepo = suggestionRepo;
		this.feedbackRepo = feedbackRepo;
	}

	/**
	 * Persists an {@link AiSuggestion} record for audit and feedback purposes.
	 *
	 * @param suggestionType
	 *            type discriminator (see
	 *            {@link com.weeklycommit.ai.provider.AiContext} constants)
	 * @param userId
	 *            requesting user
	 * @param planId
	 *            associated plan, may be null
	 * @param commitId
	 *            associated commit, may be null
	 * @param contextString
	 *            the serialised context used to produce the suggestion
	 * @param result
	 *            the provider result
	 * @return the persisted {@link AiSuggestion}
	 */
	public AiSuggestion storeSuggestion(String suggestionType, UUID userId, UUID planId, UUID commitId,
			String contextString, AiSuggestionResult result) {
		AiSuggestion s = new AiSuggestion();
		s.setSuggestionType(suggestionType);
		s.setUserId(userId);
		s.setPlanId(planId);
		s.setCommitId(commitId);
		s.setPrompt(contextString != null ? contextString : "{}");
		s.setContextHash(hash(contextString));
		s.setRationale(result.rationale());
		s.setSuggestionPayload(result.payload());
		s.setModelVersion(result.modelVersion());
		return suggestionRepo.save(s);
	}

	/**
	 * Overloaded variant that additionally stamps {@code teamId} and
	 * {@code weekStartDate} on the persisted record. Intended for TEAM_INSIGHT and
	 * PERSONAL_INSIGHT rows that need to be queried by team + week.
	 *
	 * @param suggestionType
	 *            type discriminator
	 * @param userId
	 *            requesting user
	 * @param planId
	 *            associated plan, may be null
	 * @param commitId
	 *            associated commit, may be null
	 * @param contextString
	 *            the serialised context used to produce the suggestion
	 * @param result
	 *            the provider result
	 * @param teamId
	 *            team scope, may be null
	 * @param weekStartDate
	 *            ISO week start (Monday), may be null
	 * @return the persisted {@link AiSuggestion}
	 */
	public AiSuggestion storeSuggestion(String suggestionType, UUID userId, UUID planId, UUID commitId,
			String contextString, AiSuggestionResult result, UUID teamId, LocalDate weekStartDate) {
		AiSuggestion s = storeSuggestion(suggestionType, userId, planId, commitId, contextString, result);
		s.setTeamId(teamId);
		s.setWeekStartDate(weekStartDate);
		return suggestionRepo.save(s);
	}

	/**
	 * Records user feedback on a suggestion.
	 *
	 * @param request
	 *            the feedback request
	 * @return the saved {@link AiFeedback}
	 * @throws ResourceNotFoundException
	 *             if the suggestion does not exist
	 */
	public AiFeedback recordFeedback(AiFeedbackRequest request) {
		if (!suggestionRepo.existsById(request.suggestionId())) {
			throw new ResourceNotFoundException("AI suggestion not found: " + request.suggestionId());
		}

		AiFeedback feedback = new AiFeedback();
		feedback.setSuggestionId(request.suggestionId());
		feedback.setUserId(request.userId());
		feedback.setAccepted(request.action() != AiFeedbackRequest.FeedbackAction.DISMISSED);
		feedback.setFeedbackNotes(request.notes());
		AiFeedback saved = feedbackRepo.save(feedback);

		// Also update the suggestion's accepted/dismissed flags for quick reads
		suggestionRepo.findById(request.suggestionId()).ifPresent(s -> {
			switch (request.action()) {
				case ACCEPTED, EDITED -> s.setAccepted(true);
				case DISMISSED -> s.setDismissed(true);
			}
			suggestionRepo.save(s);
		});

		log.debug("Recorded AI feedback: suggestionId={}, action={}", request.suggestionId(), request.action());
		return saved;
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	static String hash(String input) {
		if (input == null || input.isBlank()) {
			return "";
		}
		try {
			MessageDigest digest = MessageDigest.getInstance("SHA-256");
			byte[] bytes = digest.digest(input.getBytes(StandardCharsets.UTF_8));
			return HexFormat.of().formatHex(bytes);
		} catch (NoSuchAlgorithmException e) {
			log.warn("SHA-256 not available; using empty hash");
			return "";
		}
	}
}

