void generateTeamInsights_passesTeamIdAndWeekStartDate() throws Exception {
	setUpAvailableServices();
	setUpTeam();
	when(planRepo.findByTeamIdAndWeekStartDate(TEAM_ID, WEEK)).thenReturn(List.of());
